1	import { Injectable } from '@angular/core';
2	import { HttpRequest, HttpHandler, HttpEvent, HttpInterceptor, HttpHeaders } from '@angular/common/http';
3	import { Observable } from 'rxjs';
4	
5	@Injectable()
6	export class UserAuthInterceptor implements HttpInterceptor {
7	
8	  constructor() {}
9	
10	  intercept(request: HttpRequest<unknown>, next: HttpHandler): Observable<HttpEvent<unknown>> {
11	    if (!request || !(request as any).headers) {
12	      return next.handle(request);
13	    }
14	
15	    const token = localStorage.getItem('token');
16	
17	    const authRequest = token
18	      ? request.clone({
19	          setHeaders: {
20	            Authorization: token
21	          }
22	        })
23	      : request;
24	
25	    return next.handle(authRequest);
26	  }
27	}
