1	import { Injectable } from '@angular/core';
2	import { HttpRequest, HttpHandler, HttpEvent, HttpInterceptor, HttpErrorResponse } from '@angular/common/http';
3	import { Observable, throwError } from 'rxjs';
4	import { catchError } from 'rxjs/operators';
5	import { MatSnackBar } from '@angular/material/snack-bar';
6	import { getErrorMessage } from './api-error';
7	
8	/** Requests with this header fail silently (no snackbar). Used for background polling. */
9	export const SKIP_ERROR_SNACKBAR_HEADER = 'X-Skip-Error-Snackbar';
10	
11	@Injectable()
12	export class HttpErrorInterceptor implements HttpInterceptor {
13	  constructor(private snackBar: MatSnackBar) {}
14	
15	  intercept(req: HttpRequest<any>, next: HttpHandler): Observable<HttpEvent<any>> {
16	    const skipSnackbar = req.headers.has(SKIP_ERROR_SNACKBAR_HEADER);
17	    const forwardReq = skipSnackbar
18	      ? req.clone({ headers: req.headers.delete(SKIP_ERROR_SNACKBAR_HEADER) })
19	      : req;
20	
21	    return next.handle(forwardReq).pipe(
22	      catchError((err: HttpErrorResponse) => {
23	        if (!skipSnackbar) {
24	          const msg = getErrorMessage(err, req.url);
25	          console.error('[HTTP Error]', err.status, req.url, err);
26	          this.snackBar.open(msg, 'Close', {
27	            duration: err?.error?.type === 'user' ? 5000 : 8000,
28	            panelClass: err?.error?.type === 'user' ? ['warn-snackbar'] : ['error-snackbar'],
29	          });
30	        }
31	        return throwError(() => err);
32	      })
33	    );
34	  }
35	}
