395	
396	  private parseYmd(value: string | null | undefined): Date | null {
397	    if (!value) {
398	      return null;
399	    }
400	    const m = String(value).match(/^(\d{4})-(\d{2})-(\d{2})/);
401	    if (!m) {
402	      return null;
403	    }
404	    const y = Number(m[1]);
405	    const mo = Number(m[2]) - 1;
406	    const d = Number(m[3]);
407	    return new Date(y, mo, d);
408	  }
409	
410	  private fmtYmd(d: Date | null | undefined): string | null {
411	    if (!d) {
412	      return null;
413	    }
414	    const yyyy = d.getFullYear();
415	    const mm = String(d.getMonth() + 1).padStart(2, '0');
416	    const dd = String(d.getDate()).padStart(2, '0');
417	    return `${yyyy}-${mm}-${dd}`;
418	  }
