1	import { Injectable, OnDestroy } from '@angular/core';
2	import { HttpClient, HttpHeaders } from '@angular/common/http';
3	import { BehaviorSubject, interval, Subscription } from 'rxjs';
4	import { exhaustMap, startWith } from 'rxjs/operators';
5	import { environment } from 'src/environments/environment';
6	import { SKIP_ERROR_SNACKBAR_HEADER } from '../http-error.interceptor';
7	
8	export interface MentionableUser {
9	  id: number;
10	  name: string;
11	  lastname: string;
12	  email: string;
13	  profile_photo: string | null;
14	}
