26	export interface CreateNotificationPayload {
27	  userId: number;
28	  type: string;
29	  event: string;
30	  title: string;
31	  message: string;
32	}
33	
34	@Injectable({ providedIn: 'root' })
35	export class NotificationService implements OnDestroy {
36	  private readonly base = `${environment.url}/api/notifications`;
37	  private readonly POLL_INTERVAL_MS = 30_000;
38	
39	  private readonly _unreadCount = new BehaviorSubject<number>(0);
40	  readonly unreadCount$ = this._unreadCount.asObservable();
41	
42	  private _pollSub: Subscription | null = null;
43	
44	  constructor(private readonly http: HttpClient) {}
45	
46	  private headers(silent = false): HttpHeaders {
47	    const token = localStorage.getItem('token');
48	    let headers = token ? new HttpHeaders().set('Authorization', token) : new HttpHeaders();
49	    if (silent) {
50	      headers = headers.set(SKIP_ERROR_SNACKBAR_HEADER, 'true');
51	    }
52	    return headers;
53	  }
54	
55	  /** Begin polling the unread count every 30 s. No-ops if already polling. */
56	  startPolling(): void {
57	    if (this._pollSub) return;
58	    this._pollSub = interval(this.POLL_INTERVAL_MS)
59	      .pipe(
60	        startWith(0),
61	        exhaustMap(() =>
62	          this.http.get<{ count: number }>(`${this.base}/count`, { headers: this.headers(true) })
63	        )
64	      )
65	      .subscribe({
66	        next: ({ count }) => this._unreadCount.next(count),
67	        error: () => {},
68	      });
69	  }
70	
71	  stopPolling(): void {
72	    this._pollSub?.unsubscribe();
73	    this._pollSub = null;
74	  }
75	
76	  /** Force a one-shot refresh of the unread count (e.g. after marking as read). */
77	  refreshCount(): void {
78	    this.http
79	      .get<{ count: number }>(`${this.base}/count`, { headers: this.headers(true) })
80	      .subscribe({ next: ({ count }) => this._unreadCount.next(count), error: () => {} });
81	  }
82	
83	  getNotifications() {
84	    return this.http.get<{ status: boolean; data: NotificationItem[] }>(
85	      `${this.base}`,
86	      { headers: this.headers() }
87	    );
88	  }
89	
90	  markAsRead(id: number) {
91	    return this.http.patch<{ status: boolean }>(`${this.base}/${id}/read`, {}, { headers: this.headers() });
92	  }
93	
94	  markAllAsRead() {
95	    return this.http.post<{ status: boolean }>(`${this.base}/read-all`, {}, { headers: this.headers() });
96	  }
97	
98	  deleteAll() {
99	    return this.http.delete<{ status: boolean; deleted: number }>(
100	      `${this.base}`,
101	      { headers: this.headers() }
102	    );
103	  }
104	
105	  getMentionableUsers() {
106	    return this.http.get<{ status: boolean; data: MentionableUser[] }>(
107	      `${this.base}/mentionable-users`,
108	      { headers: this.headers() }
109	    );
110	  }
111	
112	  createNotification(payload: CreateNotificationPayload) {
113	    return this.http.post<{ status: boolean; data: any }>(
114	      `${this.base}/create`,
115	      payload,
116	      { headers: this.headers() }
117	    );
118	  }
119	
120	  ngOnDestroy(): void {
121	    this.stopPolling();
122	  }
123	}
