45	  /** Upload a logo file to S3 and save the resulting URL to the customer record. */
46	  uploadLogo(customerId: number, file: File): Observable<string> {
47	    const extension = file.name.split('.').pop()?.toLowerCase() ?? '';
48	    const fileName = `images-customer-logo-${customerId}-${Date.now()}.${extension}`;
49	    // file.type can be empty on some Windows browsers for webp and other formats
50	    const MIME_MAP: Record<string, string> = {
51	      jpg: 'image/jpeg', jpeg: 'image/jpeg', png: 'image/png',
52	      gif: 'image/gif', webp: 'image/webp', svg: 'image/svg+xml',
53	      avif: 'image/avif', bmp: 'image/bmp'
54	    };
55	    const contentType = file.type || MIME_MAP[extension] || 'application/octet-stream';
56	    return from(this._doLogoUpload(customerId, file, fileName, contentType));
57	  }
58	
59	  private async _doLogoUpload(customerId: number, file: File, fileName: string, contentType: string): Promise<string> {
60	    const res: any = await firstValueFrom(
61	      this.http.post(`${this.serverAddress}/getPreSignedUrl`, { fileName, contentType })
62	    );
63	    const uploadRes = await fetch(res.signedUrl, { method: 'PUT', body: file, headers: { 'Content-Type': contentType } });
64	    if (!uploadRes.ok) {
65	      throw new Error(`S3 upload failed: ${uploadRes.status}`);
66	    }
67	    const { publicUrl } = await firstValueFrom(
68	      this.http.post<{ publicUrl: string }>(`${this.serverAddress}/setObjectPublic`, { fileName })
69	    );
70	    await firstValueFrom(this.updateCustomer(customerId, { customers_logo: publicUrl }));
71	    return publicUrl;
72	  }
