1	import { Injectable } from '@angular/core'
2	import { Observable, pipe } from 'rxjs'
3	import { HttpClient, HttpParams } from '@angular/common/http'
4	import { map, catchError } from 'rxjs/operators';
5	import { HttpHeaders } from '@angular/common/http';
6	import { environment } from '../../../environments/environment';
7	import { ConfigService } from './config.service';
8	
9	@Injectable({
10	  providedIn: 'root'
11	})
12	export class SyncService {
13	  serverAddress = environment.data_sync;
14	  apiKey = this.configService.get('COLDLION_API_KEY');
15	
16	  constructor(private configService: ConfigService) { }
17	
18	  /* ====================================================================================
19	    🎨 COLDLION - API Calls
20	    ==================================================================================== */
21	
22	  streamMerchgroupDetailFromCL(data: { companyCode: string, mgTypeCode: string; divisionCode: string }): Observable<string> {
23	    const url = `${this.serverAddress}/streamMerchgroupDetailFromCL`;
24	
25	    return new Observable<string>((observer) => {
26	      fetch(url, {
27	        method: 'POST',
28	        headers: {
29	          'Content-Type': 'application/json',
30	          'X-API-Key': this.apiKey
31	        },
32	        body: JSON.stringify(data)
33	      })
34	        .then(async (response) => {
35	          if (!response.ok || !response.body) {
36	            throw new Error('Network response was not ok');
37	          }
38	
39	          const reader = response.body.getReader();
40	          const decoder = new TextDecoder();
41	
42	          let { value, done } = await reader.read();
43	
44	          while (!done) {
45	            const chunk = decoder.decode(value, { stream: true });
46	            // Emit each line separately if possible
47	            chunk.split(/\r?\n/).forEach(line => {
48	              const trimmed = line.trim();
49	              if (trimmed.startsWith("data:")) {
50	                const clean = trimmed.slice(5).trim();
51	                if (clean) observer.next(clean);
52	              }
53	            });
54	            ({ value, done } = await reader.read());
55	          }
56	
57	          observer.complete();
58	        })
59	        .catch((err) => {
60	          observer.error(err);
61	        });
62	    });
63	  }
64	}

