1	import { Injectable } from '@angular/core';
2	import { BehaviorSubject, firstValueFrom } from 'rxjs';
3	import { MainService } from './main.service';
4	
5	export interface UserProfile {
6	  firstName: string;
7	  name: string;
8	  email: string;
9	  photoUrl: string | null;
10	}
11	
12	/**
13	 * Singleton reactive store for the authenticated user's profile.
14	 * Both ToolbarUserComponent and ToolbarUserDropdownComponent inject this
15	 * so profile data and photo updates are shared without duplicate API calls.
16	 */
17	@Injectable({ providedIn: 'root' })
18	export class UserProfileService {
19	  private readonly _profile = new BehaviorSubject<UserProfile | null>(null);
20	  readonly profile$ = this._profile.asObservable();
21	
22	  private _loading = false;
23	
24	  constructor(private readonly mainService: MainService) {}
25	
26	  /** Fetch profile from backend. No-ops if already loaded or currently loading. */
27	  async loadProfile(): Promise<void> {
28	    if (this._profile.value || this._loading) return;
29	    this._loading = true;
30	    try {
31	      const profile = await firstValueFrom(this.mainService.getUserProfile());
32	      this._profile.next(profile);
33	    } catch {
34	      // Silently fail — callers fall back to JWT-decoded data
35	    } finally {
36	      this._loading = false;
37	    }
38	  }
39	
40	  /** Update photoUrl after a successful upload without re-fetching the whole profile. */
41	  setPhoto(photoUrl: string): void {
42	    const current = this._profile.value;
43	    if (current) this._profile.next({ ...current, photoUrl });
44	  }
45	
46	  /** Upload a new photo, persist to backend, then update the local profile subject. */
47	  async uploadPhoto(file: File): Promise<void> {
48	    const result = await firstValueFrom(this.mainService.uploadProfilePhoto(file));
49	    this.setPhoto(result.photoUrl);
50	  }
51	
52	  get snapshot(): UserProfile | null {
53	    return this._profile.value;
54	  }
55	}
