1	import { Injectable } from '@angular/core';
2	import { HttpClient } from '@angular/common/http';
3	import { BehaviorSubject } from 'rxjs';
4	import { environment } from '../../../environments/environment';
5	import decode from 'jwt-decode';
6	
7	@Injectable({ providedIn: 'root' })
8	export class ImpersonationService {
9	  private _isImpersonating$ = new BehaviorSubject<boolean>(!!localStorage.getItem('admin_token'));
10	  readonly isImpersonating$ = this._isImpersonating$.asObservable();
11	
12	  constructor(private http: HttpClient) {}
13	
14	  isImpersonating(): boolean {
15	    return this._isImpersonating$.value;
16	  }
17	
18	  getImpersonatedUser(): { name: string; role: string } | null {
19	    if (!this.isImpersonating()) return null;
20	    const token = localStorage.getItem('token');
21	    if (!token) return null;
22	    try {
23	      const p = decode(token) as any;
24	      return { name: p.name || '', role: p.role || '' };
25	    } catch {
26	      return null;
27	    }
28	  }
29	
30	  startImpersonation(userId: number, targetType?: 'user' | 'vendor' | 'factory'): void {
31	    this.http
32	      .post<{ token: string }>(`${environment.url}/api/admin/impersonate/${userId}`, targetType ? { targetType } : {})
33	      .subscribe({
34	        next: ({ token }) => {
35	          localStorage.setItem('admin_token', localStorage.getItem('token') || '');
36	          localStorage.setItem('token', token);
37	          this._isImpersonating$.next(true);
38	          window.location.href = '/';
39	        },
40	        error: (err) => {
41	          console.error('[ImpersonationService] start failed:', err);
42	        },
43	      });
44	  }
45	
46	  stopImpersonation(): void {
47	    const adminToken = localStorage.getItem('admin_token');
48	    if (adminToken) {
49	      localStorage.setItem('token', adminToken);
50	    }
51	    localStorage.removeItem('admin_token');
52	    this._isImpersonating$.next(false);
53	    window.location.href = '/';
54	  }
55	}
